const aiResponse = $input.item.json.response;
let data;
try {
  data = JSON.parse(aiResponse);
} catch(e) {
  data = { vendor: 'Parse Error', confidence_score: 0, anomalies: ['JSON Parse Error'] };
}

// Default Fallbacks
const cleaned = {
    vendor: data.vendor || 'Unknown Vendor',
    vendor_uid: data.vendor_uid || null,
    vendor_iban: data.vendor_iban || null,
    invoice_number: data.invoice_number || `UNKNOWN-${Date.now()}`,
    invoice_date: data.invoice_date || null,
    due_date: data.due_date || null,
    net_amount: parseFloat(data.net_amount) || 0,
    vat_amount: parseFloat(data.vat_amount) || 0,
    vat_percent: parseFloat(data.vat_percent) || 0,
    gross_amount: parseFloat(data.gross_amount) || 0,
    currency: data.currency || 'USD',
    cost_center: data.cost_center || 'General',
    confidence_score: parseFloat(data.confidence_score) || 0,
    anomalies: JSON.stringify(Array.isArray(data.anomalies) ? data.anomalies : []),
};

if (cleaned.confidence_score < 0.7) {
  cleaned.status = 'Needs Review';
} else {
  cleaned.status = 'Draft';
}

// Carry over email metadata
cleaned.email_sender = $('Email Read (IMAP)').item.json.from;
cleaned.email_subject = $('Email Read (IMAP)').item.json.subject;

return cleaned;
